package v2events

import (
	"context"

	"google.golang.org/grpc"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/plugin/v2events"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type V2EventsProxy struct {
	v2events.UnimplementedV2EventsServer
	client v2events.V2EventsClient
}

func init() {
	proxyutil.Register(&v2events.V2Events_ServiceDesc, NewV2EventsProxy)
}
func NewV2EventsProxy(cc grpc.ClientConnInterface) v2events.V2EventsServer {
	return &V2EventsProxy{client: v2events.NewV2EventsClient(cc)}
}
func (p *V2EventsProxy) Publish(ctx context.Context, in *v2events.V2EventsPublishRequest) (*v2events.V2EventsPublishResponse, error) {
	return proxyutil.ProxyMethod[v2events.V2EventsPublishRequest, v2events.V2EventsPublishResponse](p.client.Publish)(ctx, in)
}
